using NP phigrOS;
CI MAXN=1e6+5;
int n,m,a[MAXN],v[MAXN],cnt,l[MAXN],r[MAXN],vis[MAXN]; 
struct node
{
    int x,id;
    bool operator < (const node&a) const
	{
        return abs(a.x)<abs(x);
    }
};
priority_queue<node> q;
signed main(void)
{
    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>a[i];
        if(!a[i])--i,--n;
	}
	v[++cnt]=a[1];
	FOR(i,2,n)
	{
		bool x=v[cnt]<0,y=a[i]<0;
        if(x==y)
		{
			v[cnt]+=a[i];
		}
        else
		{
			v[++cnt]=a[i];
		}
	} 
    int x=0,ans=0;
    FOR(i,1,cnt)
    {
        if(v[i]>0)
		{
			++x;
			ans+=v[i];
		}
        q.push({v[i],i});
		r[i]=i+1;
		l[i]=i-1;
    }
    v[0]=v[cnt+1]=llinf;
    r[0]=1,l[cnt+1]=cnt;
	r[cnt+1]=cnt+1;
    while(x>m)
    {
        int front=q.top().id;
        q.pop();
        if(vis[front]||((l[front]==0||r[front]>cnt)&&v[front]<0))
		{
			continue;
		}
        ans-=abs(v[front]);
        v[front]+=v[l[front]]+v[r[front]];
        q.push(node{v[front],front});
        vis[l[front]]=vis[r[front]]=true;
        l[front]=l[l[front]];
		r[l[front]]=front;
        r[front]=r[r[front]];
		l[r[front]]=front;
        --x;
    }
    cout<<max(0ll,ans);
    return false;
}

