	{
		FOR(j,1,m)
		{
			cin>>c[i][j];
		}
	}
	FOR(i,1,n)
	{
		FOR(j,1,m)
		{
			if(c[i][j]!='*')continue;
			if(c[i][j-1]!='*')
			{
				p[i][j].fst=++cnt1;
