		q.push({b[i],i});
	}
	FOR(i,1,k) d.push(0);
	wh(p.size())
	{
		PII _=p.top();
		PII __=q.top();
		if(vis[_.snd]){p.pop();continue;}
		if(vis[__.snd]){q.pop();continue;}
		if(d.top()>_.fst-__.fst)sum+=_.fst,vis[_.snd]=1,p.pop();
		else
		{
			sum+=__.fst,vis[__.snd]=1;
			sum+=d.top(),d.pop(),q.pop();
            d.push(a[__.snd]-b[__.snd]);
		}
		if(sum<=m)++ans;
		else break;
	}
	cout<<ans;
    return false;
}

