CI m=998244353;
CI MAXN=1e6+5,MAXM=5e6+5;
int f[MAXN];
int d;
char c[MAXN];
int l[MAXM],r[MAXM],t;
int v[MAXM];
int dfs(int x)
{
	long long res=1;
	if(v[l[x]])
	{
		res*=v[l[x]];
	}
	else
	{
		res*=dfs(l[x]);
	}
	if(v[r[x]])
	{
		res*=v[r[x]];
	}
	else
	{
		res*=dfs(r[x]);
	}
	res++;
	res%=m;
	return res;
}
int solve()
{
	cin>>d>>c;
	if(c[0]=='1')
	{
		return f[d];
	}
	int p=1;
	t=1;
	FOR(i,1,d-1)
	{
		l[p]=++t;
		r[p]=++t;
		if(c[i]=='1')// 走右儿子
		{
			v[l[p]]=f[d-i]+1;
			if(i==d-1)
			{
				v[r[p]]=1;
			}
			else
			{
				v[r[p]]=0;
			}
			p=r[p];
		}
		else// 走左儿子
		{
			v[r[p]]=f[d-i-1]+1;
			if(i==d-1)
			{
				v[l[p]]=1;
			}
			else
			{
				v[l[p]]=0;
			}
			p=l[p];
		}
	}
	return (dfs(1)+m-1)%m;
}
