#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI mx=1e5+7,lg=17,len=1<<lg;
int n,m,q,op,l,r,ans,tr[2<<lg][32],tmp[32],res[32];
char s[32];
int qp(int a,int b)
{
    int ans=1;
    wh(b)
    {
        if(b&1)
        {
            ans=ans*a;
        }
        a=a*a;
        b>>=1;
    }
    return ans;
}
void init(int p)
{
    FOR(i,1,n)
    {
        if(s[i-1]=='1')tr[p][i]=1;
        else if(s[i-1]=='0')tr[p][i]=2;
        else tr[p][i]=0;
    }
}
void merge(int a[],int b[],int c[])
{
    int f=1;
    FOR(i,1,n)
    {
        if(a[i]==0)c[i]=b[i];
        else if(b[i]==0)c[i]=a[i];
        else if(a[i]==b[i])c[i]=a[i];
        else f=0;
    }
    if(!f)
    {
        FOR(i,1,n)
        {
            c[i]=-1;
        }
    }
}
void build()
{
    ROF(i,len-1,1)
    {
        merge(tr[i<<1],tr[i<<1|1],tr[i]);
    }
}
void upd(int x)
{
    int p=x+len-1;
    init(p);
    for(p>>=1;p>=1;p>>=1)
    {
        merge(tr[p<<1],tr[p<<1|1],tr[p]);
    }
}
void qry(int l,int r)
{
    int L=l+len-1;
    int R=r+len-1;
    FOR(i,1,n)
    {
        tmp[i]=0;
    }
    wh(L<=R)
    {
        if(L&1)
        {
            merge(tmp,tr[L],res);
            FOR(i,1,n)
            {
                tmp[i]=res[i];
            }
            L++;
        }
        if(!(R&1))
        {
            merge(tmp,tr[R],res);
            FOR(i,1,n)
            {
                tmp[i]=res[i];
            }
            R--;
        }
        L>>=1;
        R>>=1;
    }
}
signed main(void)
{
    IOS
    cin>>n>>m>>q;
    FOR(i,1,m)
    {
        cin>>s;
        init(i+len-1);
    }
    build();
    wh(q--)
    {
        cin>>op>>l;
        if(op)
        {
            cin>>s;upd(l);
        }
        else
        {
            cin>>r;
            qry(l,r);
            int ok=1,cnt=0;
            FOR(i,1,n)
            {
                if(tmp[i]==-1)
                {
                    ok=0;break;
                }
                if(tmp[i]==0)++cnt;
            }
            if(ok)
            {
                ans^=(1ll<<cnt);
            }
        }
    }
    cout<<ans;
    return false;
}

