void dfs(int u,int fa)//DFS
{
	sz[u]=1;
	FOI(s,g[u])
	{
		int v=s.fst;
		int w=s.snd;
		if(v==fa)
		{
			continue;
		}
		dfs(v,u);
		ROF(x,sz[u],0)
		{
			ROF(y,sz[v],0)
			{
				if(x+y>k)
				{
					continue;
				}
				int t=y*(k-y)+(sz[v]-y)*(n-k-sz[v]+y);
				f[u][x+y]=max(f[u][x+y],f[u][x]+f[v][y]+w*t);//树上背包dp
			}
		}
		sz[u]+=sz[v];
	}
}
