struct segtree
{
	int l,r,cnt[30],tag;
}t[200200];
void build(int p,int l,int r)
{ 
	t[p].l=l,t[p].r=r,t[p].tag=0;
	if(l==r)
    {
		t[p].cnt[s[l-1]-'A'+1]=1;
		return;
	}
	int mid=(l+r)>>1;
	build(p*2,l,mid);
	build(p*2+1,mid+1,r);
	FOR(i,1,26)
    {
		t[p].cnt[i]=t[p*2].cnt[i]+t[p*2+1].cnt[i];
	}
}
void pushdown(int p)
{
	if(t[p].tag)
    {
		t[p*2].cnt[t[p].tag]=t[p*2].r-t[p*2].l+1;
		t[p*2+1].cnt[t[p].tag]=t[p*2+1].r-t[p*2+1].l+1;
		FOR(i,1,26)
        {
			if(i!=t[p].tag)
            {
				t[p*2].cnt[i]=0;
				t[p*2+1].cnt[i]=0;
			}
		}
		t[p*2].tag=t[p].tag;
		t[p*2+1].tag=t[p].tag;
		t[p].tag=0;
	}
}
void change(int p,int l,int r,int c)
{
	if(l>r)
    {
		return ;
	}
	if(l<=t[p].l&&t[p].r<=r)
    {
		t[p].tag=c;
		t[p].cnt[c]=t[p].r-t[p].l+1;
		FOR(i,1,26)
        {
			if(i!=c){
				t[p].cnt[i]=0;
			}
		}
		return ; 
	}
	pushdown(p);
	int mid=(t[p].l+t[p].r)>>1;
	if(l<=mid)
    {
		change(p*2,l,r,c);
	}
	if(r>mid)
    {
		change(p*2+1,l,r,c);
	} 
	FOR(i,1,26)
    {
		t[p].cnt[i]=t[p*2].cnt[i]+t[p*2+1].cnt[i];
	}
}
int ask(int p,int l,int r,int c)
{
	if(l<=t[p].l&&t[p].r<=r)
    {
		return t[p].cnt[c];
	}
	pushdown(p); 
	int mid=(t[p].l+t[p].r)>>1,val=0;
	if(l<=mid)
    {
		val+=ask(p*2,l,r,c);
	}
	if(r>mid)
    {
		val+=ask(p*2+1,l,r,c);
	}
	return val;
}
