inline int getid(int __x)
{
	return lower_bound(d.begin(),d.end(),__x)-d.begin()+1;
}
bool cmp(node1 __x,node1 __y)
{
	return __x.r-__x.l<__y.r-__y.l;
}
void update(int id)
{
	t[id].maxa=max(t[ls].maxa,t[rs].maxa);
}
void work(int id,int x)
{
	t[id].lazy+=x;
	t[id].maxa+=x;
}
void pushdown(int id)
{
	int x=t[id].lazy;
	if(x)
	{
		work(ls,x);
		work(rs,x);
		t[id].lazy=0;
	}
}
void change(int id,int l,int r,int _l,int _r,int x)//线段树
{
	if(l==_l&&r==_r)
	{
		work(id,x);
		return;
	}
	pushdown(id);
	int mid=(l+r)>>1;
	if(_r<=mid)
	{
		change(ls,l,mid,_l,_r,x);
	}
	else if(_l>mid)
	{
		change(rs,mid+1,r,_l,_r,x);
	}
	else
	{
		change(ls,l,mid,_l,mid,x);
		change(rs,mid+1,r,mid+1,_r,x);
	}
	update(id);
}
