void dijkstra(int s)
{
    cli(dis);
    priority_queue<node> q;
    q.push({0,0,s});
    dis[s][0]=0;
    wh(q.size())
    {
        int d=q.top().d;
        int c=q.top().c;
        int p=q.top().p;
        q.pop();
        if(d>dis[p][c])continue;
        FOI(e,g[p])
        {
            int v=e.fst;
            int w=e.snd;
            int nd=0;
            if(d>=w)
            {
                nd=dis[p][c]+1;
            }
            else
            {
                int x=(w-d+k-1)/k;
                nd=x*k+d+1;
            }
            int nc=(c+1)%k;
            if(nd<dis[v][nc])
            {
                dis[v][nc]=nd;
                q.push({nd,nc,v});
            }
        }
    }
}
