inline int f(int x,int y)
{
	return x>y?x:y;
}
void build(int id,int lt,int rt)//建树
{
	l[id]=lt,r[id]=rt;
	int mid=(lt+rt)>>1;
	if(lt==rt)
	{
		return;
	}
	int ls=id*2,rs=id*2+1;
	build(ls,lt,mid);
	build(rs,mid+1,rt);
}
inline void ad(int id,int v)
{
	tag[id]+=v;
	sum[id]+=v;
}
inline void pd(int id)//pushdown
{
	int ls=id*2,rs=id*2+1;
	ad(ls,tag[id]);
	ad(rs,tag[id]);
	tag[id]=0;
}
void upd(int id,int x,int y,int v)//区间修改
{
	if(x<=l[id]&&y>=r[id])
	{
		ad(id,v);//加
		return;
	}
	pd(id);
	int ls=id*2,rs=id*2+1;
	if(x<=r[ls])
	{
		upd(ls,x,y,v);
	}
	if(y>=l[rs])
	{
		upd(rs,x,y,v);
	}
	sum[id]=f(sum[ls],sum[rs]);
}
int query(int id,int x,int y)//查询最大值
{
	if(x<=l[id]&&y>=r[id])
	{
		return sum[id];
	}
	int res=0;
	pd(id);
	int ls=id*2,rs=id*2+1;
	if(x<=r[ls])
	{
		res=f(res,query(ls,x,y));
	}
	if(y>=l[rs])
	{
		res=f(res,query(rs,x,y));
	}
	return res;
}
