}
int find(int x)//find
{
	if(f[x]==x)return x;
	return f[x]=find(f[x]);
}
void merge(int x,int y)//merge
{
	int fx=find(x),fy=find(y);
	if(fx!=fy)
	{
		FOR(i,1,n)
		{
			t[i]=find(i),s[i]+=w[t[i]];
		}
		FOR(i,1,n)w[t[i]]=0;
		f[fx]=fy;
	}
}
