using namespace std;
const int m=500005;
int a[m],p[m],blk[m],len,n,q;
int id[m];
PII opts[m];
struct S
{
	int mn;
	int lazy;
}tr[m<<2];
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
void pushup(int id)
{
	tr[id].mn=min(tr[ls].mn,tr[rs].mn);
}
void build(int id,int l,int r)
{
	if(l==r)
	{
		tr[id].mn=a[l];
		return;
	}
	build(ls,l,mid);
	build(rs,mid+1,r);
	pushup(id);
}
void pushdown(int id)
{
	if(tr[id].lazy)
	{
		tr[ls].lazy+=tr[id].lazy;
		tr[rs].lazy+=tr[id].lazy;
		tr[ls].mn+=tr[id].lazy;
		tr[rs].mn+=tr[id].lazy;
		tr[id].lazy=0;
	}
}
void update(int id,int l,int r,int x,int y,int v)
{
	if(x<=l&&r<=y)
	{
		tr[id].mn+=v;
		tr[id].lazy+=v;
		return;
	}
	pushdown(id);
	if(x<=mid)update(ls,l,mid,x,y,v);
	if(y>mid)update(rs,mid+1,r,x,y,v);
	pushup(id);
}
int query(int id,int l,int r,int x,int y)
{
	if(x<=l&&r<=y)
	{
		return tr[id].mn;
	}
	pushdown(id);
	int res=inf;
	if(x<=mid)res=min(res,query(ls,l,mid,x,y));//取最小值
	if(y>mid)res=min(res,query(rs,mid+1,r,x,y));
	return res;
}
int findL(int x)
{
	return id[lower_bound(blk+1,blk+1+len,x)-blk];
}
int findR(int x)
{
	return id[upper_bound(blk+1,blk+1+len,x)-blk-1];
}
void check()
{
	if(query(1,1,n,1,n)<=0)cout<<"No\n";
	else cout<<"Yes\n";
}
signed main()
{
	IOS
	cin.tie(0);
	cout.tie(0);
	cin>>n>>q;
	FOR(i,1,n)
	{
		cin>>p[i];
	}
	FOR(i,1,n)
	{
		cin>>a[i];
		if(a[i])
		{
			blk[++len]=p[i];
			id[len]=i;
		}
	}
	build(1,1,n);
	FOR(k,1,q)
	{
		check();
		int op;
		cin>>op;
		if(op&1)
		{
			int L,R;
			cin>>L>>R;
			int l=findL(L);
			int r=findR(R);
			if(l>r)continue;
			if(!l||!r)continue;
			update(1,1,n,l,r,1);
			opts[k]=mk(L,R);
		}
		else
		{
			int x;
			cin>>x;
			int l=findL(opts[x].fst);
			int r=findR(opts[x].snd);
			if(l>r)continue;
			if(!l||!r)continue;
			update(1,1,n,l,r,-1);
		}
	}
	check();
	return 0;
}

