using namespace std;
inline int read()
{
	int len = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')len = len * 10 + ch - '0', ch = getchar();
	return len * f;
}
void write(int len)
{
	if (len < 0)putchar('-'), len = -len;
	if (len > 9)write(len / 10);
	putchar(len % 10 + '0');
	return;
}
CI MAXN = 5e2 + 5;
char S[MAXN][MAXN];
int n, m, k, ans = -1, a1, a2, a3, a4, a5, A[MAXN][MAXN], B[MAXN][MAXN], C[MAXN][MAXN];
int main(void)
{
	cin >> n >> m >> k;
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= m; ++j)
		{
			cin >> S[i][j];
			A[i][j] = (S[i][j] == 'P') + A[i - 1][j];
			B[i][j] = (S[i][j] == 'B') + B[i - 1][j];
			C[i][j] = (S[i][j] == 'G') + C[i - 1][j];
		}
	}
	for (int i = 1; i <= n; ++i)
	{
		for (int j = i; j <= n; ++j)
		{
			int p = 0, b = 0, g = 0, p_ = 1, b_ = 1, g_ = 1, len = j - i + 1;
			for (int r = 1; r <= m; ++r)
			{
				p += A[j][r] - A[i - 1][r];
				b += B[j][r] - B[i - 1][r];
				g += C[j][r] - C[i - 1][r];
				if (A[j][r] - A[i - 1][r])
				{
					b_ = g_ = r + 1;
					b = g = 0;
				}
				if (B[j][r] - B[i - 1][r] || C[j][r] - C[i - 1][r])
				{
					p_ = r + 1;
					p = 0;
				}
				while (b_ <= r && len * (r - b_ + 1) - b > k)
				{
					b -= B[j][b_] - B[i - 1][b_];
					++b_;
				}
				while (g_ <= r && len * (r - g_ + 1) - g > k)
				{
					g -= C[j][g_] - C[i - 1][g_];
					++g_;
				}
				if (len * (r - p_ + 1) > ans)
				{
					ans = len * (r - p_ + 1);
					a1 = i;
					a2 = p_;
					a3 = j;
					a4 = r;
					a5 = 'P';
				}
				if (len * (r - b_ + 1) > ans)
				{
					ans = len * (r - b_ + 1);
					a1 = i;
					a2 = b_;
					a3 = j;
					a4 = r;
					a5 = 'B';
				}
				if (len * (r - g_ + 1) > ans)
				{
					ans = len * (r - g_ + 1);
					a1 = i;
					a2 = g_;
					a3 = j;
					a4 = r;
					a5 = 'G';
				}
			}
		}
	}
	for (int i = a1; i <= a3; ++i)
	{
		for (int j = a2; j <= a4; ++j)
		{
			S[i][j] = a5;
		}
	}
	cout << ans << '\n';
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= m; ++j)
		{
			cout << S[i][j];
		}
		cout << '\n';
	}
	return false;
}

