const int N=1000005;
int n,m,st[N][30],lg[N];
il int qu(int l,int r)
{
	if(l>r)return -1;
	int k=lg[r-l+1];
	return max(st[l][k],st[r-(1<<k)+1][k]);
}
signed main(void)
{
	n=read();
	FOR(i,1,n)
	{
		int v=read();
		st[i][0]=v;
		st[i+n][0]=v;
		st[i+n+n][0]=v;
	}
	if(n==1)
	{
		read();
		write(-1);
		pc(' ');
		return 0;
	}
	m=n+n+n;
	lg[1]=0;
	FOR(i,2,m)lg[i]=lg[i>>1]+1;
	FOR(j,1,lg[m])
	{
		FOR(i,1,m-(1<<j)+1)
		{
			st[i][j]=max(st[i][j-1],st[i+(1<<(j-1))][j-1]);
		}
	}
	FOR(i,1,n)
	{
		int b=read();
		int p=i+n;
		if(qu(p+1,p+n-1)<b)
		{
			write(-1);
			pc(' ');
			continue;
		}
		int l=1,r=n/2,ans=-1;
		wh(l<=r)
		{
			int md=mid;
			int mx=max(qu(p-md,p-1),qu(p+1,p+md));
			if(mx>=b)
			{
				ans=md;
				r=md-1;
			}
			else
			{
				l=md+1;
			}
		}
		if(ans==-1)write(-1);
		else write(ans);
		pc(' ');
	}
	return false;
}

