using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 5e5 + 5;
ll a[MAXN], n, m, cnt[MAXN];
void solve()
{
	memset(cnt, 0, sizeof cnt);
	n = read(), m = read();
	ll ans = 0;
	for (int i = 1; i <= n; ++i)a[i] = read();
	ll r = 0;
	for (int l = 1; l < n; ++l)
	{
		for (; r < n && (a[r] != a[r + 1] || r < l);)
		{
			++r;
			if (r >= l + m - 1)
			{
				++cnt[a[r]];
			}
		}
		ans += max(0ll, r - (l + m - 1) + 1 - cnt[a[l]]);
		if (r >= l + m - 1)--cnt[a[l + m - 1]];
	}
	write(ans);
	puts("");
}
int main(void)
{
	int t = read();
	while (t--)
	{
		solve();
	}
	return false;
}

