			fix(x,a[x]^y,x%2);
			a[x]=y;
		}
		else
		{
			if((x^y)%2)
			{
				puts("0"); 
				continue;
			}
			writeln(get_sum(x-1,x%2)^get_sum(y,x%2));
		}
	}
