using NP phigrOS;
struct edge
{
	int v, next;
} e[500005];
int head[500005], t[500005], n, m, cnt;
void addedge(int u, int v)
{
	e[++cnt].v = v;
	e[cnt].next = head[u];
	head[u] = cnt;
}
int in[500005];
priority_queue<int, vector<int>, greater<int> >q;
void solve()
{
	memcpy(in, t, sizeof(t));
	for (int i = 1; i <= n; i++)
		if (!in[i])q.push(i);
	int maxp = 0, ans = 0;
	while (!q.empty())
	{
		int u = q.top();
		q.pop();
		if (u > maxp)ans++, maxp = u;
		for (int i = head[u]; i; i = e[i].next)
		{
			int v = e[i].v;
			in[v]--;
			if (!in[v])q.push(v);
		}
	}
	printf("%lld\n", ans);
}
set<int> s;
void solve2()
{

	memcpy(in, t, sizeof(t));
	for (int i = 1; i <= n; i++)
		if (!in[i])s.insert(i);
	int maxp = 0, ans = 0;
	while (!s.empty())
	{
		int u;
		if (maxp > *s.begin())
		{
			u = *s.begin();
			s.erase(u);
		}
		else
		{
			auto it = s.end();
			it--;
			u = *it;
			s.erase(u);
		}
		if (u > maxp)ans++, maxp = u;
		for (int i = head[u]; i; i = e[i].next)
		{
			int v = e[i].v;
			in[v]--;
			if (!in[v])s.insert(v);
		}
	}
	printf("%lld\n", ans);
}
signed main(void)
{
	n = read(), m = read();
	for (int i = 1; i <= m; i++)
	{
		int u, v;
		u = read(), v = read();
		addedge(u, v);
		t[v]++;
	}
	solve();
	solve2();
	return false;
}

