ull p[N],f[N][M];
char s[M][N];
int n,mn=inf,len[M];
signed main(void)
{
    n=read();
    FOR(i,1,n)
    {
        cin>>s[i]+1;
        len[i]=strlen(s[i]+1);
        mn=min(mn,len[i]);
    }
    p[0]=1;
    FOR(i,1,mn)p[i]=p[i-1]*131;
    FOR(i,1,n)FOR(j,1,len[i])f[j][i]=f[j-1][i]*131+(s[i][j]-'a'+1);
    int l=0,r=mn,ans=0;
    wh(l<=r)
    {
        CI md=mid;
        bool fd=0;
        if(md==0)
        {
            fd=1;
            ans=md;
            l=md+1;
            continue;
        }
        FOR(st,1,len[1]-md+1)
        {
            ull th=f[st+md-1][1]-f[st-1][1]*p[md];
            bool ac=1;
            FOR(k,2,n)
            {
                bool cc=0;
                FOR(ps,1,len[k]-md+1)
                {
                    ull ch=f[ps+md-1][k]-f[ps-1][k]*p[md];
                    if(ch==th)
                    {
                        cc=1;
                        break;
                    }
                }
                if(!cc)
                {
                    ac=0;
                    break;
                }
            }
            if(ac)
            {
                fd=1;
                ans=md;
                break;
            }
        }
        if(fd)l=md+1;
        else r=md-1;
    }
    writeln(ans);
    return 0;
}

