CI MAXN=1e5+5;
int dis[MAXN],si[MAXN],st[MAXN],n,m,t,nxt[MAXN],ans=0;
vector<PII> g[MAXN];
vector<int>tree[MAXN];
void dijkstr(int s)
{
	priority_queue<PII,vector<PII>,greater<>> pq;
	cli(dis);
	cl(st);
	pq.push(mk(0,s));
	dis[s]=0;
	wh(pq.size())
	{
		PII front=pq.top();
		int b=front.snd;
		pq.pop();
		if(st[b])continue;
		st[b]=true;
		FOI(u,g[b])
		{
			if(dis[u.fst]>dis[b]+u.snd)
			{
				dis[u.fst]=dis[b]+u.snd;
				nxt[u.fst]=b;
				pq.push(mk(dis[u.fst],u.fst));
			}
            if(dis[u.fst]==dis[b]+u.snd&&nxt[u.fst]>b)
				nxt[u.fst]=b;
		}
	}
}
void dfs(int u,int fa)
{
	FOI(s,tree[u])
	{
		if(s==fa)continue;
		dfs(s,u);
		si[u]+=si[s];
	}
	ans=max(ans,(dis[u]-t)*si[u]);
}
