void dj1(int s)
{
	for(int i=1;i<=n;i++)d1[i]=inf;
    d1[s]=0;
    priority_queue<node>Q;
    Q.push((node){s,0});
    while(!Q.empty())
    {
        node ch=Q.top();
        Q.pop();
        int u=ch.u;
        int d=ch.d;
        if(d!=d1[u])continue;
        for(int i=head[u];i;i=a[i].next)
        {
            int x=a[i].to,y=a[i].quan;
            if(d1[u]+y<d1[x]){
                d1[x]=d1[u]+y;
                Q.push((node){x,d1[x]});
            }
        }
    }
}

void dj2(int s)
{
	for(int i=1;i<=n;i++)d2[i]=inf;
    d2[s]=0;
    priority_queue<node> Q;
    Q.push((node){s,0});
    while(!Q.empty())
    {
        node ch=Q.top();
        Q.pop();
        int u=ch.u;
        int d=ch.d;
        if(d!=d2[u])continue;
        for(int i=head[u];i;i=a[i].next)
        {
            int x=a[i].to,y=a[i].quan;
            if(d2[u]+y<d2[x])
            {
                d2[x]=d2[u]+y;
                Q.push((node){x,d2[x]});
            }
        }
    }
}
void dj3(int s)
{

	FOR(i,1,n)d3[i]=inf;
    d3[s]=0;
    priority_queue<node> Q;
    Q.push((node){s,0});
    while(!Q.empty())
    {
        node ch=Q.top();
        Q.pop();
        int u=ch.u,d=ch.d;
        if(d!=d3[u])continue;
        for(int i=head[u];i;i=a[i].next)
        {
            int x=a[i].to,y=a[i].quan;
