void pushup(int o)
{
	sum[o]=sum[o*2]+sum[o*2+1];
	minn[o]=min(minn[o*2],minn[o*2+1]);
}
void pushdown(int o,int l,int r)
{
	if(lz[o])
	{
		int mid=(l+r)/2;
		sum[o*2]+=lz[o]*(mid-l+1);
		minn[o*2]+=lz[o];
		lz[o*2]+=lz[o];
		sum[o*2+1]+=lz[o]*(r-mid);
		minn[o*2+1]+=lz[o];
		lz[o*2+1]+=lz[o];
		lz[o]=0;
	}
}
void build(int l=1,int r=n,int o=1)
{
	if(l==r)
	{
		sum[o]=a[l];
		minn[o]=a[l];
		return;
	}
	int mid=(l+r)/2;
	build(l,mid,o*2);
	build(mid+1,r,o*2+1);
	pushup(o);
}
void upadd(int s,int e,int k,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		sum[o]+=k*(r-l+1);
		minn[o]+=k;
		lz[o]+=k;
		return;
	}
	int mid=(l+r)/2;
	pushdown(o,l,r);
	if(s<=mid) upadd(s,e,k,l,mid,o*2);
	if(mid+1<=e) upadd(s,e,k,mid+1,r,o*2+1);
	pushup(o);
}
int qrymin(int s,int e,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		return minn[o];
	}
	int mid=(l+r)/2;
	pushdown(o,l,r);
	int res=inf;
	if(s<=mid) res=min(res,qrymin(s,e,l,mid,o*2));
	if(mid+1<=e) res=min(res,qrymin(s,e,mid+1,r,o*2+1));
	return res;
}
int qrysum(int s,int e,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		return sum[o];
	}
	int mid=(l+r)/2;
	pushdown(o,l,r);
	int res=0;
	if(s<=mid) res+=qrysum(s,e,l,mid,o*2);
	if(mid+1<=e) res+=qrysum(s,e,mid+1,r,o*2+1);
	return res;
}
