void pushdown(int p)
{
	if(t[p].lz)
    {
		t[p<<1].val=(t[p<<1].r-t[p<<1].l+1)-t[p<<1].val;
		t[p<<1].lz^=t[p].lz;
		t[p<<1|1].val=(t[p<<1|1].r-t[p<<1|1].l+1)-t[p<<1|1].val;
		t[p<<1|1].lz^=t[p].lz;
