const int N=1e4+10,mod=1e9+9;
ll n, dp[N][10][10];
map<int, int> primes;
inline bool check(int x)
{
	for (int i = 2; i * i <= x; i++)
	{
		if (x % i == 0) return false;
	}
	return true;
}
signed main(void)
{
	cin >> n;
	int tot = 0;
	for (int i = 100; i <= 999; i++)
	{
		if (check(i))
		{
			tot++, primes[i] = 1;
			int x = i - i / 100 * 100;
			int first = x / 10, second = x % 10;
			dp[3][first][second]++;
		}
	}
	for (int i = 4; i <= n; i++)
	{
		for (int j = 0; j <= 9; j++)
		{
			for (int k = 0; k <= 9; k++)
			{
				for (int l = 0; l <= 9; l++)
				{
					int num = j * 100 + k * 10 + l;
					if (primes[num])
					{
						dp[i][k][l] += dp[i - 1][j][k];
						dp[i][k][l] %= mod;
					}
				}
			}
		}
	}
	ll ans = 0;
	for (int i = 0; i <= 9; i++)
		for (int j = 0; j <= 9; j++)ans += dp[n][i][j], ans %= mod;
	cout << ans;
	return 0;
}

