	IOS
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>a[i];
	}
	build(1,n,1);
	FOR(i,1,m)
	{
		int cmd;
		cin>>cmd;
		if(cmd==1)
		{
			int l,r,k;
			cin>>l>>r>>k;
			add(l,r,k);
		}
		if(cmd==2)
		{
			int k;
			cin>>k;
			add(1,1,k);
		}
		if(cmd==3)
		{
			int k;
			cin>>k;
			add(1,1,-k);
		}
		if(cmd==4)
		{
			int l,r;
			cin>>l>>r;
			cout<<query(l,r)<<'\n';
		}
		if(cmd==5)
        {
            cout<<query(1,1)<<'\n';
        }
	}
    return false;
}

