CI MAXN=1e5+5;
int n,m,a[MAXN],b[MAXN],w,t,sum[MAXN],mid;
bool dfs(int x, int l)
{
	if(t-w<sum[mid])return false;
	if(x==0)return true;
	bool flag=0;
	FOR(i,l,n)
	{
		if(a[i]>=b[x])
		{
			a[i]-=b[x];
			if(a[i]<b[1])w+=a[i];
			if(b[x-1]==b[x])flag=dfs(x-1,i);
			else flag=dfs(x-1,1);
			if(a[i]<b[1])w-=a[i];
			a[i]+=b[x];
			if(flag)return true;
		}
	}
	return false;
}
