int n,m,t;
void pu(int q,int tr[])
{
	tr[q]=tr[ls(q)]+tr[rs(q)];
}
void up(int q,int l,int r,int p,int v,int tr[])
{
	if(l==r)
	{
		tr[q]+=v;
		return;
	}
	int md=(l+r)>>1;
	if(p<=md)up(ls(q),l,md,p,v,tr);
	else up(rs(q),md+1,r,p,v,tr);
	pu(q,tr);
}
int qry(int q,int l,int r,int ql,int qr,int tr[])
{
	if(ql>qr)return 0;
	if(l>=ql&&r<=qr)return tr[q];
	int md=(l+r)>>1,res=0;
	if(ql<=md)res+=qry(ls(q),l,md,ql,qr,tr);
	if(qr>md)res+=qry(rs(q),md+1,r,ql,qr,tr);
	return res;
}
int qp(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
