CI MAXN=2005;
/*
1.
f[u][j]表示以u为根的子树，总共花费j的容量，能获得的最大价值
2.
只选u自己，容量>=v[u]时价值为w[u]
FOR(i,v[u],m)f[u][i]=w[u];
3.
给子树to分配k的容量，剩余容量给u本身和之前的子树
*/
int n,m,f[MAXN][MAXN],w[MAXN],v[MAXN],rt;
vector<int> g[MAXN];
void dfs(int u)
{
	FOR(i,v[u],m)f[u][i]=w[u];
	FOR(i,0,(int)g[u].size()-1)
	{
		int to=g[u][i];
		dfs(to);
		ROF(j,m,v[u])
			FOR(k,0,j-v[u])
				f[u][j]=max(f[u][j],f[u][j-k]+f[to][k]);
	}
}
