	FOR(i,1,n)
	{
        int p;
		cin>>p>>w[i];
		v[i]=1;
		if(p==-1)rt=i;
		else g[p].pb(i);
	}
	dfs(rt);
	cout<<f[rt][m];
	return false;
}

