const int maxn = 1005;
int n, m, s, t, g[maxn][maxn], in[maxn], a[maxn], b[maxn], h[maxn], f[maxn];
queue<int>q;
void topsort()
{
	for (int i = 1; i <= n; i++)
	{
		if (!in[i])
		{
			q.push(i);
			f[i] = 1;
		}
	}
	int ans = 1;
	while (!q.empty())
	{
		int u = q.front();
		q.pop();
		ans = max(ans, f[u]);
		for (int i = 1; i <= n; i++)
		{
			if (!g[u][i])
			{
				continue;
			}
			in[i] -= g[u][i];
			f[i] = max(f[i], f[u] + 1);
			if (!in[i])
			{
				q.push(i);
			}
		}
	}
	cout << ans;
}
