	if(dep>s.size())
    {
        return;
    }
	if(dep==s.size()&&p[nw])
	{
		sum=max(sum,p[nw]+1);
		return;
	}
	int ch=s[dep]-'a';
	if(!fg)
	{
		if(dep<s.size())
        {
            dfs(nw,dep+1,1,s);
        }
		FOR(i,0,25)
		{
			if(trie[nw][i])
			{
				dfs(trie[nw][i],dep,1,s);
				if(i!=ch)
                {
                    dfs(trie[nw][i],dep+1,1,s);
                }
			}
		}
	}
	if(trie[nw][ch])
    {
        dfs(trie[nw][ch],dep+1,fg,s);
    }
}
