CI mx=32,sz=400010;
int s[mx][sz],lz[mx][sz];
int l,t,o;
void pu(int x,int k)
{
	s[x][k]=s[x][k*2]+s[x][k*2+1];
}
void pd(int x,int k,int le,int ri)
{
	if(!lz[x][k])
	{
		return;
	}
	int mid=(le+ri)/2;
	if(lz[x][k]==1)
	{
		s[x][k*2]=mid-le+1;
		s[x][k*2+1]=ri-mid;
		lz[x][k*2]=1;
		lz[x][k*2+1]=1;
	}
	if(lz[x][k]==-1)
	{
		s[x][k*2]=0;
		s[x][k*2+1]=0;
		lz[x][k*2]=-1;
		lz[x][k*2+1]=-1;
	}
	lz[x][k]=0;
}
void bd(int x,int k,int le,int ri)
{
	lz[x][k]=0;
	if(le==ri)
	{
		s[x][k]=1;
		return;
	}
	int mid=(le+ri)/2;
	bd(x,k*2,le,mid);
	bd(x,k*2+1,mid+1,ri);
	pu(x,k);
}
void up(int x,int k,int le,int ri,int ql,int qr,int v)
{
	if(ri<ql||le>qr)
	{
		return;
	}
	if(le>=ql&&ri<=qr)
	{
		if(v==1)
		{
			s[x][k]=ri-le+1;
			lz[x][k]=1;
		}
		else
		{
			s[x][k]=0;
			lz[x][k]=-1;
		}
		return;
	}
	pd(x,k,le,ri);
	int mid=(le+ri)/2;
	up(x,k*2,le,mid,ql,qr,v);
	up(x,k*2+1,mid+1,ri,ql,qr,v);
	pu(x,k);
}
int q(int x,int k,int le,int ri,int ql,int qr)
{
	if(ri<ql||le>qr)
	{
		return 0;
	}
	if(le>=ql&&ri<=qr)
	{
		return s[x][k];
	}
	pd(x,k,le,ri);
	int mid=(le+ri)/2;
	return q(x,k*2,le,mid,ql,qr)+q(x,k*2+1,mid+1,ri,ql,qr);
}
