void solve()
{
	cin>>n>>m;
	wh(!s.empty())
	{
		s.pop();
	}
	FOR(i,1,n)
	{
		cin>>a[i];
		r[i]=a[i];
		wh(!d[i].empty())
		{
			d[i].pop();
		}
