	}
	FOR(i,1,n)
	{
		int f=d[i].front();
		d[i].pop();
		s.push(mk(f,i));
	}
	ans=0;
	FOR(i,1,m)
	{
		int len=x[i]-x[i-1];
		wh(len>0)
		{
			if(s.empty())
			{
				break;
			}
			PII top=s.top();
			s.pop();
			if(a[top.snd]==0)
			{
				continue;
			}
			if(a[top.snd]<=len)
			{
				len-=a[top.snd];
				a[top.snd]=0;
			}
			else
			{
				a[top.snd]-=len;
				len=0;
				s.push(top);
				break;
			}
		}
		if(len>0)
		{
			ans+=x[i]-x[i-1]-len;
			break;
		}
		else
		{
			a[t[i]]=r[t[i]];
			int fi=inf,se=t[i];
			if(!d[se].empty())
			{
				fi=d[se].front();
				d[se].pop();
			}
			if(!s.empty())
			{
				if(s.top().snd==se)
				{
					s.pop();
				}
			}
			s.push(mk(fi,se));
			ans+=x[i]-x[i-1];
		}
	}
	FOR(i,1,n)
	{
		ans+=a[i];
	}
	cout<<ans<<'\n';
}
