bool check(int u)
{
    cli(d);
    cl(w);
    d[1]=0;
    priority_queue<PII,vector<PII>,greater<>> q;
    q.push(mk(0,1));
    while(!q.empty())
	{
        PII cur=q.top();
		q.pop();
        int dd=cur.fst,x=cur.snd;
        if(w[x]||f[x]>u)
		{
			continue;
		}
        if(dd!=d[x])
		{
			continue;
		}
