		{
            int y=e.fst,z=e.snd;
            if(f[y]>u)
			{
				continue;
			}
            if(d[y]>d[x]+z)
			{
                d[y]=d[x]+z;
                q.push(mk(d[y],y));
            }
        }
    }
    return d[n]<=b;
