#define ls(x) x<<1
#define rs(x) x<<1|1
CI mx=1e5+5;
int n,m;
int a[mx],d[mx];
struct st
{
	int l,r,s,ad;
}t[mx*4];
void pd(int p)
{
	if(t[p].ad)
	{
		t[ls(p)].ad+=t[p].ad;
		t[rs(p)].ad+=t[p].ad;
		t[ls(p)].s+=(t[ls(p)].r-t[ls(p)].l+1)*t[p].ad;
		t[rs(p)].s+=(t[rs(p)].r-t[rs(p)].l+1)*t[p].ad;
		t[p].ad=0;
	}
}
void bd(int p,int l,int r)
{
	t[p].l=l;
	t[p].r=r;
	t[p].ad=0;
	if(l==r)
	{
		t[p].s=d[l];
		return;
	}
	int mid=(l+r)/2;
	bd(ls(p),l,mid);
	bd(rs(p),mid+1,r);
	t[p].s=t[ls(p)].s+t[rs(p)].s;
}
void up(int p,int l,int r,int x)
{
	if(l<=t[p].l&&t[p].r<=r)
	{
		t[p].s+=(t[p].r-t[p].l+1)*x;
		t[p].ad+=x;
		return;
	}
	pd(p);
	int mid=(t[p].l+t[p].r)/2;
	if(l<=mid)up(ls(p),l,r,x);
	if(r>mid)up(rs(p),l,r,x);
	t[p].s=t[ls(p)].s+t[rs(p)].s;
}
int qry(int p,int l,int r)
{
	if(l<=t[p].l&&t[p].r<=r)
	{
		return t[p].s;
	}
	pd(p);
	int mid=(t[p].l+t[p].r)/2;
	int res=0;
	if(l<=mid)res+=qry(ls(p),l,r);
	if(r>mid)res+=qry(rs(p),l,r);
	return res;
}
