CI N=200005;
int n,mx,c[N];
vector<int>e[N];
PII dfs(int u,int f)
{
	int w=0,b=0;
	FOI(v,e[u])
	{
		if(v==f)continue;
		PII t=dfs(v,u);
		int wl=t.fst,bl=t.snd;
		if(b!=0)mx=max(mx,wl+b);
		if(w!=0)mx=max(mx,bl+w);
		w=max(w,wl);
		b=max(b,bl);
	}
	if(c[u]==0)mx=max(mx,b);
	else mx=max(mx,w);
	PII r;
	r.fst=r.snd=-1e9;
	if(c[u]==0)r.fst=1;
	else r.snd=1;
	if(w!=0)r.fst=w+1;
	if(b!=0)r.snd=b+1;
	return r;
}
