using NP phigrOS;
CI MAXN=1e3+5,dx[]={-1,0,1,0},dy[]={0,1,0,-1};
int n,m,vis[MAXN][MAXN];
char g[MAXN][MAXN];
PII boy,girl,ghost[2];
bool check(int x,int y,int tim)
{
	if(x<1||x>n||y<1||y>m||g[x][y]=='X')
	{
		return false;
	}
	FOR(i,0,1)
	{
		if(abs(x-ghost[i].fst)+abs(y-ghost[i].snd)<=tim*2)
		{
			return false;
		}
	}
	return true;
}
int bfs()
{
	int tim=0;
	memset(vis,0,sizeof vis);
	queue<PII> qb,qg;
	qb.push(boy);
	qg.push(girl);
	wh(qb.size()||qg.size())
	{
		++tim;
        FOR(i,0,2)
        {
            int bs=qb.size()-1;
            FOR(i,0,bs)
    		{
    			PII t=qb.front();
    			qb.pop();
    			int x=t.fst,y=t.snd;
    			if(!check(x,y,tim))
    			{
    				continue;
    			}
    			FOR(k,0,3)
    			{
    				int a=x+dx[k],b=y+dy[k];
    				if(check(a,b,tim))
    				{
    					if(vis[a][b]==2) 
    					{
    						return tim;	
    					}
    					if(!vis[a][b])
    					{
    						vis[a][b]=1;
    						qb.push({a,b});
    					}
    				}
    			}
    		}
        }

		FOR(i,0,0)
		{
            int gs=qg.size()-1;
			FOR(j,0,gs)
			{
				PII t=qg.front();
				qg.pop();
				int x=t.fst,y=t.snd;
				if(!check(x,y,tim))
				{
					continue;
				}
				FOR(k,0,3)
				{
					int a=x+dx[k],b=y+dy[k];
					if(check(a,b,tim))
					{
						if(vis[a][b]==1)
						{
							return tim;
						}
						if(!vis[a][b])
						{
							vis[a][b]=2;
							qg.push({a,b});
						}
					}
				}
			}			
		}
	}
	return -1;
}
