using NP phigrOS;
int n, m;
struct node
{
	vector<int> next;
	int size, nextsize;
	__int128 p, q;
} a[100010];
queue<int>q;
signed main(void)
{
	cin >> n >> m;
	for (int i = 1; i <= n; i++)
	{
		cin >> a[i].nextsize;
		for (int j = 1; j <= a[i].nextsize; j++)
		{
			int y;
			cin >> y;
			a[i].next.push_back(y);
			a[y].size++;
		}
	}
	for (int i = 1; i <= n; i++)
	{
		if (a[i].size == 0)
		{
			q.push(i);
			a[i].p = 1, a[i].q = 1;
		}
	}
	while (!q.empty())
	{
		int t = q.front();
		q.pop();
		__int128 fenzi = a[t].p, fenmu = a[t].q * a[t].nextsize;
		if (fenmu == 0)continue;
		for (int i = 0; i < a[t].nextsize; i++)
		{
			int k = a[t].next[i];
			a[k].size--;
			if (a[k].size == 0)q.push(k);
			if (a[k].q == 0)
			{
				a[k].p = fenzi;
				a[k].q = fenmu;
			}
			else
			{
				__int128 gcd = __gcd(a[k].q, fenmu);
				a[k].p = a[k].p * (fenmu / gcd) + fenzi * (a[k].q / gcd);
				a[k].q = a[k].q * (fenmu / gcd);
			}
		}
	}
	for (int i = 1; i <= n; i++)
	{
		if (a[i].nextsize == 0)
		{
			__int128 gcd = __gcd(a[i].p, a[i].q);
			a[i].p /= gcd;
			a[i].q /= gcd;
			write(a[i].p);
			pc(' ');
			writeln(a[i].q);
		}
	}
	return false;
}

