using namespace std;
inline UOLL_ATE read(){
	UOLL_ATE x=0; char s=getchar();
	while(!isdigit(s))s=getchar();
	while(isdigit(s))x=(x<<1)+(x<<3)+s-'0',s=getchar();
	return x;
}UOLL_ATE n,m,c,k,l,ans,o;
int main(void){
	n=read(),m=read(),c=read(),k=read();
	for(UOLL_ATE i=0;i<n;i++)l|=read();
	for(UOLL_ATE i=1;i<=m;i++)o|=1ull<<read(),read();
	for(UOLL_ATE i=0;i<k;i++)ans+=!((o>>i)&1)||((l>>i)&1);
	if(ans==64&&!n)cout<<"18446744073709551616";
	else cout<<(ans==64?-n:(1ull<<ans)-n);
	return false;
}

