bool ju[1005][1005]={false};
vector<int> ss,cc;
void d(int x,int y)
{
	if(a[x-1][y]=='#') b[x][y]++;
	if(a[x+1][y]=='#') b[x][y]++;
	if(a[x][y+1]=='#') b[x][y]++;
	if(a[x][y-1]=='#') b[x][y]++;	
}
void dfs(int x,int y)
{
	if(ju[x][y]==false||x<1||x>n||y<1||y>n) return;
	ju[x][y]=false;
	s++;
	c+=4-b[x][y];
	dfs(x-1,y);
	dfs(x+1,y);
	dfs(x,y+1);
	dfs(x,y-1);			
}
