{
	cin>>n;
	FOR(i,1,n)
	    FOR(j,1,n)
	    {
	    	cin>>a[i][j];
	    	if(a[i][j]=='#') ju[i][j]=true;
	    }
	FOR(i,1,n)
	    FOR(j,1,n) if(a[i][j]=='#') d(i,j); 
	FOR(i,1,n)
	    FOR(j,1,n)
		{
			if(ju[i][j]==true)
			{
				dfs(i,j);
				ss.pb(s);
				s=0;
				cc.pb(c);
				c=0; 
			}
