CI MAXN=1e5+5;
int st[MAXN],n,m,dis[MAXN],s;
vector<PII> g[MAXN];
void dijkstra(int s)
{
	cli(dis);
	cl(st);
	priority_queue<PII,vector<PII>,greater<>> q;
	dis[s]=0;
	q.push(mk(0,s));
	wh(q.size())
	{
		PII f=q.top();
		q.pop();
		int b=f.snd;
		if(st[b])continue;
        st[b]=1;
		FOI(s,g[b])
		{
			if(dis[s.fst]>dis[b]+s.snd)
			{
				dis[s.fst]=dis[b]+s.snd;
				q.push(mk(dis[s.fst],s.fst));
			}
		}
	}
} 
