CI MAXN=5e5+5;
int sum[MAXN],n,m,a[MAXN],ans=0;
vector<int> s;
void fix(int x,int k)
{
	for(int i=x;i<=n;i+=lowbit(i))
	{
		sum[i]+=k;
	}
}
int get_sum(int x)
{
	int s=0;
	for(int i=x;i;i-=lowbit(i))
	{
		s+=sum[i];
	}
	return s;
}
int find(int x)
{
	return lower_bound(s.begin(),s.end(),x)-s.begin()+1;
}
