{
	memset(treen, 0x3f3f3f3f, sizeof(treen));
	cin >> n >> m;
	for (int i = 1; i <= n; i++)
	{
		cin >> a[i];
		_add(i, a[i]);
	}
	for (int i = 1; i <= m; i++)
	{
		cin >> l >> r;
		cout << _findmax(l, r) - _findmin(l, r) << "\n";
	}
	return false;
}

