#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI dx[]={0,-1,0,1},dy[]={-1,0,1,0};
CI MAXN=3e2+5;
int n,m;
int begin_x,begin_y,begin_time;
char c[MAXN][MAXN],vis[MAXN][MAXN];
struct node
{
	int x,y,time;
};
struct csm
{
	int x_one,y_one,x_two,y_two;
};
map<char,csm> mp;
bool check(int x,int y)
{
	return !(vis[x][y]||(x<1||x>n)||(y<1||y>m)||(c[x][y]=='#'));
}
int BFS()
{
	queue<node> q;
	q.push({begin_x,begin_y,begin_time});
	while(q.size())
	{
		int now_x=q.front().x;
		int now_y=q.front().y;
		int now_time=q.front().time;
		q.pop();
		
		for(int i=0;i<4;++i)
		{
			int new_x=now_x+dx[i];
			int new_y=now_y+dy[i];
			if(c[new_x][new_y]=='=')return now_time+1;
			if(check(new_x,new_y))
			{
				vis[new_x][new_y]=true;
				if(c[new_x][new_y]>='A'&&c[new_x][new_y]<='Z')
				{
					csm cs=mp[c[new_x][new_y]];
					if(cs.x_one==new_x&&cs.y_one==new_y)
					{
						new_x=cs.x_two;
						new_y=cs.y_two;
					}
					else
					{
						new_x=cs.x_one;
						new_y=cs.y_one;
					}
				}
				q.push({new_x,new_y,now_time+1}); 
			}
		}
	}return -1;
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d%d\n",&n,&m);
	for(int i=1;i<=n;++i)
	{
		for(int j=1;j<=m;++j)
		{
			c[i][j]=getchar();
			if(c[i][j]=='@')
			{
				begin_x=i;
				begin_y=j;
				begin_time=0;
			}
			if(c[i][j]>='A'&&c[i][j]<='Z')
			{
				if(mp.find(c[i][j])==mp.end())
				{
					mp[c[i][j]].x_one=i;
					mp[c[i][j]].y_one=j;
				}
				else
				{
					mp[c[i][j]].x_two=i;
					mp[c[i][j]].y_two=j;
				}
			}
		}
		getchar();
	}
	printf("%d",BFS());
	return false;
}

