CI MAXN=5e5+5;
int a[MAXN],n,b[MAXN],c[MAXN],m,d[MAXN],f;
bool check(int x)
{
	FOR(i,1,m)
	{
		d[i]=0;
	}
	FOR(i,1,n)
	{
		d[a[i]]+=b[i];
	}
	FOR(i,1,m)
	{
        if(d[i]<x)return false;
		d[i]-=x;
	}
	int tmp=x;
	FOR(i,1,n)
	{
		if(d[a[i]]>0&&c[i])
		{
			--d[a[i]];
			--tmp;
		}
	} 
	return (tmp<=0);
} 
int find_ans()
{
	int l=0,r=f,ans=0;
	wh(l<=r)
	{
		int mid=(l+r)>>1; 
		if(check(mid))l=mid+1,ans=mid;
		else r=mid-1;
	}
	return ans;
}
