CI MAXN=1e5+5;
int n,t,a[MAXN][5],ans;
priority_queue<int> q[4];
void solve()
{
    n=read();
    FOR(i,1,3)
    {
        wh(!q[i].empty())
        {
            q[i].pop();
        }
    }
    ans=0;
    FOR(i,1,n)
    {
        int c=0,cx=0;
        FOR(j,1,3)
        {
            a[i][j]=read();
            if(!c||a[i][j]>a[i][c])
            {
                cx=c;
                c=j;
            }
            else if(!cx||a[i][j]>a[i][cx])
            {
                cx=j;
            }
        }
        ans+=a[i][c];
        q[c].push(a[i][cx]-a[i][c]);
    }
    FOR(i,1,3)
    {
        wh(q[i].size()>(n>>1))
        {
            ans+=q[i].top();
            q[i].pop();
        }
    }
    writeln(ans);
}
signed main(void)
{
    ROF(t,read(),1)
    {
        solve();
    }
