const int maxn = 5005, max2 = (1 << 20) + 5, MOD = 998244353;
int n, a[maxn], f[maxn][maxn];
ll fp(int p)
{
	if (p == 0)
	{
		return 1;
	}
	ll ans = fp(p >> 1);
	ans = (ans * ans) % MOD;
	if (p & 1)
	{
		ans = (ans << 1) % MOD;
	}
	return ans;
}
int main(void)
{
	cin >> n;
	for (int i = 1; i <= n; ++i)
	{
		cin >> a[i];
	}
	sort(a + 1, a + n + 1);
	int maxx = a[n];
	f[0][0] = 1;
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 0; j <= maxx; ++j)
		{
			if(j>=a[i])f[i][j] = (f[i - 1][j] + f[i - 1][j - a[i]]) % MOD;
            else f[i][j] = f[i - 1][j];
		}
	}
	ll ans = 0, sum = 0;
	for (int i = 3; i <= n; ++i)
	{
		sum = 0;
		for (int j = 0; j <= a[i]; ++j)
		{
			sum += f[i - 1][j];
			sum %= MOD;
		}
		ans = ((ans - sum + fp(i - 1)) % MOD + MOD) % MOD;
	}
	cout << ans ;
	return false;
}

