using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e4+5;

vector<int> g[MAXN];
int w[MAXN],sz[MAXN],f[MAXN],n,ans = inf;

void dfs1(int u, int fa, int dep)
{
	f[1] += w[u] * dep;
	sz[u] = w[u];
	for (auto s : g[u])
	{
		if (s == fa) continue;
		dfs1(s, u, dep + 1);
		sz[u] += sz[s];
	}
}
void dfs2(int u, int fa)
{
	for (auto s : g[u])
	{
		if (s == fa) continue;
		f[s] = f[u] - sz[s] + sz[1] - sz[s];
		dfs2(s, u);
	}
}
int main(void)
{
	cin >> n;
	int  v1, v2;
	for (int u = 1; u <= n; ++u)
	{
		cin >> w[u] >> v1 >> v2;
		if (v1)
		{
			g[u].push_back(v1);
			g[v1].push_back(u);
		}
		if (v2)
		{
			g[u].push_back(v2);
			g[v2].push_back(u);
		}
	}
	dfs1(1, -1, 0);
	dfs2(1, -1);
	for (int i = 1; i <= n; ++i)ans = min(ans, f[i]);
	cout << ans;
	return false;
}

