int n,m,a,b;
bool check(int mid)
{
    int ua=a*mid,ub=b*mid;
    int tmp;
    if(ua>n){
        tmp=(ua-n+a-b-1)/(a-b);
        ua-=tmp*(a-b);
        ub+=tmp*(a-b);
    }
    return (ua<=n&&ub<=m);
}
signed main()
{
    scanf("%lld%lld%lld%lld",&n,&m,&a,&b);
    if(n<m)swap(n,m);
    if(a<b)swap(a,b);
    int l=0,r=n;
    int best=0;
    while(l<=r){
        int mid=l+(r-l)/2;
        if(check(mid)==1){
            best=max(best,mid);
            l=mid+1;
        }else{
            r=mid-1;
        }
    }
    printf("%lld",best);
    return 0;
}

