struct Pos{
    int x,y;
    Pos(int ax = 0, int ay = 0) {
        x=ax;
        y=ay;
    }
};
void bfs(int x,int y) {
    queue<Pos> q;
    q.push(Pos(x,y));
    while(q.size()){
        Pos now=q.front(); 
        q.pop();
        int x=now.x,y=now.y;
        if(x<1||x>n)continue;
        if(y<1||y>m)continue;
        if(a[x][y]=='0')continue;
        if(vis[x][y])continue;
        vis[x][y]=1;
        q.push(Pos(x+1,y));
        q.push(Pos(x-1,y));
        q.push(Pos(x,y+1));
        q.push(Pos(x,y-1));
    }
}
