long long kisten(int k,string x){
	stack<int> st;
	long long ans=0;
	for(int i=x.size()-1;i>=0;i--){
		if(x[i]>='A'&&x[i]<='Z'){
			st.push(int(x[i]-'A')+10);
		}
		else{
			st.push(int(x[i]-'0'));
		}
	}
	while(st.size()){
		ans+=(st.top())*(pow(k,st.size()-1));
		st.pop();
	}
	return ans;
}
string tenisk(int k,int n){
	stack<int> s;
	string ans;
	while(n){
		s.push(n%k);
		n/=k;
	}
	while(s.size()){
		if(s.top()>=10){
			ans+=char('A'+s.top()-10);
		}
		else ans+=char('0'+s.top());
		s.pop();
	}
	return ans;
}
