int dp[MAX_T];

int main() {
    int T, M;
    scanf("%d %d", &T, &M);

    int t[MAX_M], v[MAX_M];
    for (int i = 1; i <= M; i++) {
        t[i]=fast_read(),v[i]=fast_read();
    }

    memset(dp, 0, sizeof(dp));

    for (int i = 1; i <= M; i++) {
        for (int j = T; j >= t[i]; j--) {
            if (dp[j - t[i]] + v[i] > dp[j]) {
                dp[j] = dp[j - t[i]] + v[i];
            }
        }
    }
    printf("%d\n", dp[T]);

    return 0;
}

