#include <bits/stdc++.h>
using namespace std;
struct node{
	int a,b,c,sum,m,yb;
}a[100010];
bool cmp(node x,node y) {
	if(x.sum!=y.sum)return (x.sum>y.sum);
	if(x.a+x.b!=y.a+y.b)return (x.a+x.b>y.a+y.b);
	if(max(x.a,x.b)!=max(y.a,y.b))return (max(x.a,x.b)>max(y.a,y.b));
	return false;
}
bool Cmp(node x,node y){if((max(x.a,x.b)!=max(y.a,y.b))||(x.a+x.b!=y.a+y.b)||(x.sum!=y.sum))return true;return false;}
bool CMP(node x,node y){return x.yb<y.yb;}
int main(void){
	int n;
	cin>>n;
	for(int i=0;i<n;i++)cin>>a[i].a>>a[i].b>>a[i].c,a[i].sum=a[i].a+a[i].b+a[i].c,a[i].yb=i;
	sort(a,a+n,cmp);
	a[0].m=1;
	for(int i=1;i<n;i++){
		if(Cmp(a[i],a[i-1])){
			a[i].m=1; 
			for(int j=i;j>=0;j--){
				if(cmp(a[j],a[i]))a[i].m++;
			}
		}
		else a[i].m=a[i-1].m;
	}
	sort(a,a+n,CMP);
	for(int i=0;i<n;i++)cout<<a[i].m<<"\n";
	return false;
}

