struct nd
{
    int u,d;
    bool operator < (const nd &rhs) const
    {
        return d>rhs.d;
    }
};
priority_queue<nd> q;
bitset<mxn> vs,fl;
int n,m,k;
int dij(int st)
{
    wh(!q.empty())q.pop();
    vs.reset();
    cli(ds);
    q.push((nd){st,0});ds[st]=0;
    wh(!q.empty())
    {
        nd fi=q.top();q.pop();
        int u=fi.u;if(fl[u]&&u!=st)return ds[u];
        if(!vs[u])
        {
            vs[u]=1;
            FOI(e,g[u])
            {
                int v=e.fst,w=e.snd;
                if(ds[v]>ds[u]+w)
                {
                    ds[v]=ds[u]+w;
                    q.push((nd){v,ds[v]});
                }
            }
        }
    }
    return llinf;
}
