#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
const int MAXN = 2e6 + 10;   // 放大数组，避免离散化越界
const ll INF = 0x3f3f3f3f3f3f3f3f;

ll t[MAXN << 2];
int n, m;
ll lz[MAXN << 2];
int l[MAXN], r[MAXN], x[MAXN];
ll y[MAXN];
int ll_[MAXN], rr_[MAXN];   // 避开关键字 ll
vector<int> v;
map<int, ll> mp;
ll a[MAXN];

// 线段树向上更新
void pushup(int o)
{
    t[o] = max(t[o << 1], t[o << 1 | 1]);
}

// 下传懒标记（只保留区间加，删掉无用lzz）
void pushdown(int o, int l, int r)
{
    if (lz[o] == 0) return;
    int mid = (l + r) / 2;
    int ls = o << 1, rs = o << 1 | 1;

    t[ls] += lz[o];
    lz[ls] += lz[o];
    t[rs] += lz[o];
    lz[rs] += lz[o];
    lz[o] = 0;
}

// 建树
void build(int l, int r, int o)
{
    if (l == r)
    {
        t[o] = a[l];
        return;
    }
    int mid = (l + r) / 2;
    build(l, mid, o << 1);
    build(mid + 1, r, o << 1 | 1);
    pushup(o);
}

// 区间最大值查询
ll query(int ql, int qr, int l, int r, int o)
{
    if (ql > qr) return -INF;   // 空区间直接返回极小值
    if (ql <= l && r <= qr)
    {
        return t[o];
    }
    pushdown(o, l, r);
    int mid = (l + r) / 2;
    ll res = -INF;
    if (ql <= mid) res = max(res, query(ql, qr, l, mid, o << 1));
    if (qr > mid) res = max(res, query(ql, qr, mid + 1, r, o << 1 | 1));
    return res;
}

int main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n;
    for (int i = 1; i <= n; ++i)
    {
        cin >> x[i] >> y[i];
        v.push_back(x[i]);
    }
    cin >> m;
    for (int i = 1; i <= m; ++i)
    {
        cin >> l[i] >> r[i];
        v.push_back(l[i]);
        v.push_back(r[i]);
    }

    // 离散化
    sort(v.begin(), v.end());
    v.erase(unique(v.begin(), v.end()), v.end());
    int sz = v.size();

    // 初始化数组为极小值（正确写法，适配long long）
    for (int i = 1; i <= sz; ++i)
        a[i] = -INF;

    // 处理已知温度点
    for (int i = 1; i <= n; ++i)
    {
        int pos = lower_bound(v.begin(), v.end(), x[i]) - v.begin() + 1;
        x[i] = pos;
        a[pos] = y[i];
        mp[x[i]] = y[i];
    }

    // 处理询问区间离散化
    for (int i = 1; i <= m; ++i)
    {
        ll_[i] = lower_bound(v.begin(), v.end(), l[i]) - v.begin() + 1;
        rr_[i] = lower_bound(v.begin(), v.end(), r[i]) - v.begin() + 1;
    }

    // 建树
    build(1, sz, 1);

    // 处理每个询问
    for (int i = 1; i <= m; ++i)
    {
        int L = ll_[i], R = rr_[i];
        int oriL = l[i], oriR = r[i];
        ll maxMid = query(L + 1, R - 1, 1, sz, 1);

        bool hasL = mp.count(L);
        bool hasR = mp.count(R);
        ll valL = hasL ? mp[L] : -INF;
        ll valR = hasR ? mp[R] : -INF;

        // 判断false的条件
        bool flagFalse = false;
        if (hasL && maxMid >= valL) flagFalse = true;
        if (hasR && maxMid >= valR) flagFalse = true;
        if (hasL && hasR && valR >= valL) flagFalse = true;

        if (flagFalse)
        {
            cout << "false\n";
        }
        // 两端都有数据 + 原区间和离散后区间长度相等 = true
        else if (hasL && hasR && (oriR - oriL) == (R - L))
        {
            cout << "true\n";
        }
        // 其余情况 maybe
        else
        {
            cout << "maybe\n";
        }
    }

    return 0;
}

