using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;
ll n, c, d[MAXN], k[MAXN],e;
vector<PII> Edge[MAXN];
void dfs(int u, int fa)
{
	for (int i = 0; i < Edge[u].size(); ++i)
	{
		int s = Edge[u][i].first;
		if (s == fa) continue;
		d[s] = d[u] + Edge[u][i].second;
		k[s] = k[u] + 1;
		if (d[s] > d[c]) c = s;
		dfs(s, u);
	}
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read();
	for (int i = 1, u, v, d; i < n; ++i)
	{
		u = read(), v = read(), d = read();
		Edge[u].push_back(mk(v, d));
		Edge[v].push_back(mk(u, d));
	}
	dfs(1, -1);
	d[c] = 0;e=c;
	dfs(c, -1);
	write(d[c]);
	puts("");
	write(k[c]-k[e]-1);
	return false;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <unordered_map>
using namespace std;

struct Board {
    vector<vector<int>> grid;
    int n;
    int empty_count;

    Board(int size) : n(size), grid(size, vector<int>(size)), empty_count(0) {}

    bool operator==(const Board& other) const {
        return grid == other.grid;
    }
};

namespace std {
    template<>
    struct hash<Board> {
        size_t operator()(const Board& b) const {
            size_t h = 0;
            for (const auto& row : b.grid) {
                for (int val : row) {
                    h = h * 31 + val;
                }
            }
            return h;
        }
    };
}

int black_wins = 0, white_wins = 0, draws = 0;

bool is_valid_move(const Board& board, int x, int y, int player) {
    if (board.grid[x][y] != -1) return false;
    int opponent = 1 - player;
    int n = board.n;
    bool valid = false;

    // Check all 8 directions
    int dx[] = {-1, -1, -1, 0, 0, 1, 1, 1};
    int dy[] = {-1, 0, 1, -1, 1, -1, 0, 1};

    for (int d = 0; d < 8; ++d) {
        int nx = x + dx[d];
        int ny = y + dy[d];
        bool found_opponent = false;
        while (nx >= 0 && nx < n && ny >= 0 && ny < n && board.grid[nx][ny] == opponent) {
            nx += dx[d];
            ny += dy[d];
            found_opponent = true;
        }
        if (found_opponent && nx >= 0 && nx < n && ny >= 0 && ny < n && board.grid[nx][ny] == player) {
            valid = true;
            break;
        }
    }
    return valid;
}

vector<pair<int, int>> get_valid_moves(const Board& board, int player) {
    vector<pair<int, int>> moves;
    for (int i = 0; i < board.n; ++i) {
        for (int j = 0; j < board.n; ++j) {
            if (is_valid_move(board, i, j, player)) {
                moves.emplace_back(i, j);
            }
        }
    }
    return moves;
}

Board make_move(Board board, int x, int y, int player) {
    int opponent = 1 - player;
    board.grid[x][y] = player;
    board.empty_count--;

    int n = board.n;
    int dx[] = {-1, -1, -1, 0, 0, 1, 1, 1};
    int dy[] = {-1, 0, 1, -1, 1, -1, 0, 1};

    for (int d = 0; d < 8; ++d) {
        int nx = x + dx[d];
        int ny = y + dy[d];
        vector<pair<int, int>> to_flip;
        while (nx >= 0 && nx < n && ny >= 0 && ny < n && board.grid[nx][ny] == opponent) {
            to_flip.emplace_back(nx, ny);
            nx += dx[d];
            ny += dy[d];
        }
        if (nx >= 0 && nx < n && ny >= 0 && ny < n && board.grid[nx][ny] == player) {
            for (auto& pos : to_flip) {
                board.grid[pos.first][pos.second] = player;
            }
        }
    }
    return board;
}

