CI MAXN = 2e3 + 10, tx[] = {1, -1, 0, 0}, ty[] = {0, 0, 1, -1};
int n, m, a[MAXN][MAXN], times[MAXN][MAXN], vis[MAXN][MAXN], t;
PII memory[MAXN][MAXN];
queue<PII> q;
stack<char> path;
char c;
string s;
void solve()
{
	cin >> n >> m;
	for (int i = 1; i <= n; ++i)
	{
		cin >> s;
		s = ' ' + s;
		for (int j = 1; j <= m; ++j)
		{
			a[i][j] = s[j] - '0';
			vis[i][j] = 0;
			times[i][j] = inf;
		}
	}
	q.push({1, 1});
	times[1][1] = 0;
	while (!q.empty())//并风扇(BFS(广度优先搜索))
	{

		int now_x = q.front().first;
		int now_y = q.front().second;
		q.pop();
		for (int i = 0; i < 4; ++i)
		{
			int new_x = now_x + tx[i];
			int new_y = now_y + ty[i];
			if (new_x >= 1 && new_x <= n && new_y >= 1 && new_y <= m && a[now_x][now_y] != a[new_x][new_y] && !vis[new_x][new_y])
			{
				vis[new_x][new_y] = 1;
				times[new_x][new_y] = times[now_x][now_y] + 1;
				memory[new_x][new_y] = {now_x, now_y};
				q.push({new_x, new_y});
			}
		}
	}
	if (times[n][m] == inf)
	{
		puts("-1");
		return;
	}
	else
	{
		cout << times[n][m] << '\n';
	}
	int pointer_of_x = n, pointer_of_y = m;
	while (pointer_of_x != 1 || pointer_of_y != 1) //逆推
	{
		if (memory[pointer_of_x][pointer_of_y].first > pointer_of_x)path.push('U');
		else if (memory[pointer_of_x][pointer_of_y].first < pointer_of_x)path.push('D');
		else if (memory[pointer_of_x][pointer_of_y].second > pointer_of_y)path.push('L');
		else path.push('R');
		pointer_of_x = memory[pointer_of_x][pointer_of_y].first;
		pointer_of_y = memory[pointer_of_x][pointer_of_y].second;
	}
	while (path.size())
	{
		putchar(path.top());
		path.pop();
	}
	puts("");
}
int main(void)
{
	cin >> t;
	while (t--)
	{
		solve();
	}
	return false;
}

