int lca(int u, int v)
{
	if (dep[u] < dep[v])swap(u, v);
	int i = -1, j;
	while ((1 << (i + 1)) <= dep[u])++i ;
	for (j = i; j >= 0; --j )
		if (dep[u] - (1 << j) >= dep[v])u = f[u][j];
	if (u == v)return u;
	for (j = i; j >= 0; --j )
	{
		if (f[u][j] != f[v][j])
		{
			u = f[u][j];
			v = f[v][j];
		}
	}
	return f[u][0];
}
